// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract BayesianOracleSimple {

    // Fixed-point scale

    uint256 public constant SCALE = 1_000_000;

    // PRIORS (da JSON)

    uint256 public P_CC_TRUE;
    uint256 public P_AD_TRUE;

    // CPTs: [CC][AD]
   
    uint256[2][2] public CPT_PA;
    uint256[2][2] public CPT_PT;
    uint256[2][2] public CPT_CO;
    uint256[2][2] public CPT_DB;


    // CONSTRUCTOR
   
    constructor(
        uint256 _pCcTrue,
        uint256 _pAdTrue,
        uint256[2][2] memory cptPA,
        uint256[2][2] memory cptPT,
        uint256[2][2] memory cptCO,
        uint256[2][2] memory cptDB
    ) {
        P_CC_TRUE = _pCcTrue;
        P_AD_TRUE = _pAdTrue;

        CPT_PA = cptPA;
        CPT_PT = cptPT;
        CPT_CO = cptCO;
        CPT_DB = cptDB;
    }

    // prior_cc
 
    function priorCC(bool cc) public view returns (uint256) {
        return cc ? P_CC_TRUE : (SCALE - P_CC_TRUE);
    }

    // prior_ad
    
    function priorAD(bool ad) public view returns (uint256) {
        return ad ? P_AD_TRUE : (SCALE - P_AD_TRUE);
    }

    // p_evidence
    
    function pEvidence(
    uint8 ev,      // 0=PA, 1=PT, 2=CO, 3=DB
    bool evValue,
    bool cc,
    bool ad
) public view returns (uint256) {

    uint256 pTrue;

    if (ev == 0) {
        pTrue = CPT_PA[cc ? 1 : 0][ad ? 1 : 0];
    } else if (ev == 1) {
        pTrue = CPT_PT[cc ? 1 : 0][ad ? 1 : 0];
    } else if (ev == 2) {
        pTrue = CPT_CO[cc ? 1 : 0][ad ? 1 : 0];
    } else if (ev == 3) {
        pTrue = CPT_DB[cc ? 1 : 0][ad ? 1 : 0];
    } else {
        revert("Unknown evidence");
    }

    return evValue ? pTrue : (SCALE - pTrue);
}

    // infer_posteriors
    
    function inferPosteriors(
        bool pa,
        bool pt,
        bool co,
        bool db
    )
        public
        view
        returns (
            uint256 pCcTrue,
            uint256 pAdTrue,
            uint256[4] memory jointPost
        )
    {
        bool[4] memory evs = [pa, pt, co, db];

        uint256[4] memory jointUnnorm;
        uint256 Z = 0;

        // combinazioni CC, AD:
        // 0: (F,F)
        // 1: (F,T)
        // 2: (T,F)
        // 3: (T,T)
        for (uint256 i = 0; i < 4; i++) {
            bool cc = (i >= 2);
            bool ad = (i % 2 == 1);

            uint256 prob = priorCC(cc) * priorAD(ad) / SCALE;

            // moltiplica per TUTTE le evidenze
            for (uint256 ev = 0; ev < 4; ev++) {
                prob = prob * pEvidence(uint8(ev), evs[ev], cc, ad) / SCALE;
            }

            jointUnnorm[i] = prob;
            Z += prob;
        }

        require(Z > 0, "Normalization error");

        // normalizzazione
        for (uint256 i = 0; i < 4; i++) {
            jointPost[i] = jointUnnorm[i] * SCALE / Z;
        }

        // margini
        // P(CC = true) = (T,F) + (T,T)
        pCcTrue = jointPost[2] + jointPost[3];

        // P(AD = true) = (F,T) + (T,T)
        pAdTrue = jointPost[1] + jointPost[3];
    }
}
